#![expect(
    clippy::expect_used,
    clippy::unwrap_used,
    clippy::indexing_slicing,
    reason = "integration tests use expect/unwrap for assertion clarity"
)]
//! Behavioural test: `cf_status` returns a typed `StatusSummary`.
//!
//! Slice: state_view — cf_status structured output.
//!
//! Given: a project with work items in multiple phases and statuses
//! When:  `cf_status` is called
//! Then:  the response deserialises into a `StatusSummary` where every phase
//!        entry carries exactly {ready, in_progress, done, abandoned} counts
//!        and the counts match the work items that were added.
//!
//! The conductor must be able to deserialise the response into this typed
//! structure regardless of kernel version, so the shape is part of the public
//! contract — not a raw blob.

use cfk_core::types::phase::PhaseKind;
use cfk_core::types::routing::WorkType;
use cfk_engine::forge::MemoryForge;
use cfk_mcp::server::{BacklogAddParams, CfkServer, InitParams, PhaseFilterParams};
use rmcp::handler::server::wrapper::Parameters;
use rmcp::model::{CallToolResult, RawContent};
use serde::Deserialize;
use tempfile::TempDir;

// ── Semantic response types ───────────────────────────────────────────────────
//
// These are the types the conductor needs to pin to. The production `cf_status`
// handler must emit JSON that round-trips through these exact fields. Any field
// rename or omission breaks the contract and the test.

/// Per-phase counts in a status dashboard entry.
///
/// `abandoned` is distinct from `done` — items abandoned mid-flight must be
/// surfaced so the conductor can decide whether to requeue them.
#[derive(Debug, Deserialize, PartialEq, Eq)]
pub struct PhaseStatusCounts {
    /// Snake-case phase name (matches `PhaseKind` serde representation).
    pub phase: String,
    /// Items ready to be claimed and worked.
    pub ready: usize,
    /// Items currently claimed and in flight.
    pub in_progress: usize,
    /// Items completed and accepted.
    pub done: usize,
    /// Items that were abandoned before completion.
    pub abandoned: usize,
}

/// Typed status summary — the full response contract for `cf_status`.
///
/// The conductor deserialises the raw MCP tool result into this type; if the
/// shape changes in an incompatible way, deserialisation fails and the
/// conductor's dashboard breaks.
#[derive(Debug, Deserialize)]
pub struct StatusSummary {
    /// Project identifier for correlation and display.
    pub project_id: String,
    /// One entry per phase that has at least one work item.
    pub phases: Vec<PhaseStatusCounts>,
}

// ── Test helpers ──────────────────────────────────────────────────────────────

fn make_server(dir: &TempDir) -> CfkServer {
    CfkServer::load_with_forge(dir.path().to_path_buf(), MemoryForge::new())
        .expect("server load should succeed on empty directory")
}

fn is_error(result: &CallToolResult) -> bool {
    result.is_error.unwrap_or(false)
}

fn result_text(result: &CallToolResult) -> String {
    result
        .content
        .iter()
        .filter_map(|c| {
            if let RawContent::Text(t) = &c.raw {
                Some(t.text.as_str())
            } else {
                None
            }
        })
        .collect::<Vec<_>>()
        .join("")
}

async fn init_project(server: &CfkServer, dir: &TempDir) {
    let result = server
        .cf_init(Parameters(InitParams {
            project_root: Some(dir.path().to_str().unwrap().to_string()),
        }))
        .await
        .expect("cf_init should not return McpError");
    assert!(!is_error(&result), "cf_init failed: {}", result_text(&result));
}

// ── Scenario ──────────────────────────────────────────────────────────────────

/// Given a project with:
///   - 2 Development work items in Ready status
///   - 1 Review work item in Ready status
/// When `cf_status` is called
/// Then the JSON response deserialises into `StatusSummary` and the Development
///      phase entry reports ready=2, in_progress=0, done=0, abandoned=0 and the
///      Review phase entry reports ready=1, in_progress=0, done=0, abandoned=0.
#[tokio::test]
async fn cf_status_returns_typed_status_summary_with_correct_counts() {
    let dir = TempDir::new().expect("tempdir");
    let server = make_server(&dir);
    init_project(&server, &dir).await;

    // Add two Development items.
    for description in ["Implement login slice", "Implement logout slice"] {
        let add_result = server
            .cf_backlog_add(Parameters(BacklogAddParams {
                phase: PhaseKind::Development,
                work_type: WorkType::OuterBehavioralTestWriting,
                description: description.to_string(),
            }))
            .await
            .expect("cf_backlog_add should not return McpError");
        assert!(
            !is_error(&add_result),
            "cf_backlog_add failed: {}",
            result_text(&add_result)
        );
    }

    // Add one Review item.
    let add_review = server
        .cf_backlog_add(Parameters(BacklogAddParams {
            phase: PhaseKind::Review,
            work_type: WorkType::PrCommentTriage,
            description: "Review PR for login".to_string(),
        }))
        .await
        .expect("cf_backlog_add should not return McpError");
    assert!(
        !is_error(&add_review),
        "cf_backlog_add (review) failed: {}",
        result_text(&add_review)
    );

    // Call cf_status.
    let status_result = server
        .cf_status(Parameters(PhaseFilterParams { phase: None }))
        .await
        .expect("cf_status should not return McpError");
    assert!(
        !is_error(&status_result),
        "cf_status returned a tool error: {}",
        result_text(&status_result)
    );

    // The raw response must be valid JSON.
    let raw = result_text(&status_result);
    assert!(!raw.is_empty(), "cf_status response should not be empty");

    // CRITICAL: deserialise into the typed `StatusSummary`.
    // This is the contract assertion — if the JSON shape does not match the
    // semantic type, serde returns an Err and the test fails with a clear
    // "unknown field / missing field" message instead of a silent wrong value.
    let summary: StatusSummary = serde_json::from_str(&raw)
        .unwrap_or_else(|e| panic!("cf_status response did not deserialise into StatusSummary: {e}\nRaw response: {raw}"));

    assert!(
        !summary.project_id.is_empty(),
        "StatusSummary.project_id must be non-empty"
    );

    // Locate the Development phase entry.
    let dev_entry = summary
        .phases
        .iter()
        .find(|p| p.phase == "development")
        .unwrap_or_else(|| {
            panic!(
                "StatusSummary.phases must contain a 'development' entry; got: {:?}",
                summary.phases.iter().map(|p| &p.phase).collect::<Vec<_>>()
            )
        });

    assert_eq!(
        dev_entry.ready, 2,
        "development phase must have 2 ready items"
    );
    assert_eq!(
        dev_entry.in_progress, 0,
        "development phase must have 0 in_progress items"
    );
    assert_eq!(
        dev_entry.done, 0,
        "development phase must have 0 done items"
    );
    assert_eq!(
        dev_entry.abandoned, 0,
        "development phase must have 0 abandoned items"
    );

    // Locate the Review phase entry.
    let review_entry = summary
        .phases
        .iter()
        .find(|p| p.phase == "review")
        .unwrap_or_else(|| {
            panic!(
                "StatusSummary.phases must contain a 'review' entry; got: {:?}",
                summary.phases.iter().map(|p| &p.phase).collect::<Vec<_>>()
            )
        });

    assert_eq!(
        review_entry.ready, 1,
        "review phase must have 1 ready item"
    );
    assert_eq!(
        review_entry.abandoned, 0,
        "review phase must have 0 abandoned items"
    );
}
